export function getPost(slug: string): Post | undefined {
  return POSTS.find((p) => p.slug === slug);
}

export function getRelatedPosts(slug: string, count = 2): Post[] {
  const post = getPost(slug);
  // Prefer posts from same series, then recent posts
  const sameSeries = post?.series
    ? POSTS.filter((p) => p.slug !== slug && p.series === post.series)
    : [];
  const others = POSTS.filter(
    (p) => p.slug !== slug && !sameSeries.includes(p)
  );
  return [...sameSeries, ...others].slice(0, count);
}
